        m.insert("inverse".to_string(), Value::Null);
        m.insert("taker".to_string(), self.safe_number_k(fees.clone(), "taker", &[]));
        m.insert("maker".to_string(), self.safe_number_k(fees.clone(), "maker", &[]));
